class Student:
    def __init__(self, name, height, weight):
        self.name = name
        self.height = height
        self.weight = weight

    def __str__(self):
        return f"{self.name} {self.height} {self.weight}"

di = {}

n = int(input())
for _ in range(n):
    s, name, height, weight = input().split()
    height = int(height)
    weight = int(weight)
    student = Student(name, height, weight)
    if di.get(s) is None or di[s].height < student.height:
        di[s] = student

for s, student in sorted(di.items()):
    print(s, student)
